INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('14b78448-c464-bb37-f6e4-3751b1df448a','en','Garanti Kompozit','garanti-kompozit','<p>Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quotations.</p>','Garanti Kompozit','[]','{}','Garanti Kompozit — Sultan Defense','Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quot',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
