INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('462309f7-3d91-80ed-29b4-2c4a6c074b91','en','Dorce','dorce','<p>Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quotations.</p>','Dorce','[]','{}','Dorce — Sultan Defense','Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quot',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('462309f7-3d91-80ed-29b4-2c4a6c074b91','tr','Dorce','dorce','<p>Sultan Defense''in doğrulanmış üretici ve tedarikçi ağının bir parçası. B2B tedarik, teknik şartname ve ihracata hazır teklifler için ihracat ekibimizle iletişime geçin.</p>','Dorce','[]','{}','Dorce — Sultan Defense','Sultan Defense''in doğrulanmış üretici ve tedarikçi ağının bir parçası. B2B tedarik, teknik şartname ve ihracata hazır teklifler için ihracat ekibimizle iletişim',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('462309f7-3d91-80ed-29b4-2c4a6c074b91','de','Dorce','dorce','<p>Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen und exportfertige Angebote.</p>','Dorce','[]','{}','Dorce — Sultan Defense','Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen un',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('462309f7-3d91-80ed-29b4-2c4a6c074b91','ar','Dorce','dorce','<p>جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.</p>','Dorce','[]','{}','Dorce — Sultan Defense','جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('462309f7-3d91-80ed-29b4-2c4a6c074b91','ru','Dorce','dorce','<p>Часть проверенной сети производителей и поставщиков Sultan Defense. Свяжитесь с нашим экспортным отделом для B2B-закупок, технических характеристик и готовых к экспорту предложений.</p>','Dorce','[]','{}','Dorce — Sultan Defense','Часть проверенной сети производителей и поставщиков Sultan Defense. Свяжитесь с нашим экспортным отделом для B2B-закупок, технических характеристик и готовых к ',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
