INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('0e4d2e22-f170-7b5e-703a-bf0f21ecc1d2','en','Gurdesan','gurdesan','<p>Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quotations.</p>','Gurdesan','[]','{}','Gurdesan — Sultan Defense','Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quot',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('0e4d2e22-f170-7b5e-703a-bf0f21ecc1d2','tr','Gurdesan','gurdesan','<p>Sultan Defense''in doğrulanmış üretici ve tedarikçi ağının bir parçası. B2B tedarik, teknik şartname ve ihracata hazır teklifler için ihracat ekibimizle iletişime geçin.</p>','Gurdesan','[]','{}','Gurdesan — Sultan Defense','Sultan Defense''in doğrulanmış üretici ve tedarikçi ağının bir parçası. B2B tedarik, teknik şartname ve ihracata hazır teklifler için ihracat ekibimizle iletişim',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('0e4d2e22-f170-7b5e-703a-bf0f21ecc1d2','de','Gurdesan','gurdesan','<p>Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen und exportfertige Angebote.</p>','Gurdesan','[]','{}','Gurdesan — Sultan Defense','Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen un',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('0e4d2e22-f170-7b5e-703a-bf0f21ecc1d2','ar','Gurdesan','gurdesan','<p>جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.</p>','Gurdesan','[]','{}','Gurdesan — Sultan Defense','جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
