INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('3939e9d3-f373-4306-f372-ebc31dc3f918','de','Asisguard','asisguard','<p>Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen und exportfertige Angebote.</p>','Asisguard','[]','{}','Asisguard — Sultan Defense','Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen un',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('3939e9d3-f373-4306-f372-ebc31dc3f918','ar','Asisguard','asisguard','<p>جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.</p>','Asisguard','[]','{}','Asisguard — Sultan Defense','جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
