INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('4bc3bd1c-5376-5c12-6e52-3988860c6e87','en','Raff Military Textile','raff-military-textile','<p>Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quotations.</p>','Raff Military Textile','[]','{}','Raff Military Textile — Sultan Defense','Part of Sultan Defense''s verified manufacturer and supplier network. Contact our export team for B2B procurement, technical specifications and export-ready quot',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
