INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('760de015-56e1-08e1-553e-9db1668ac9ad','de','Milsoft','milsoft','<p>Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen und exportfertige Angebote.</p>','Milsoft','[]','{}','Milsoft — Sultan Defense','Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen un',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('760de015-56e1-08e1-553e-9db1668ac9ad','ar','Milsoft','milsoft','<p>جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.</p>','Milsoft','[]','{}','Milsoft — Sultan Defense','جزء من شبكة الموردين والمصنّعين المعتمدة لدى Sultan Defense. تواصل مع فريق التصدير لدينا للحصول على التوريد B2B والمواصفات الفنية وعروض الأسعار الجاهزة للتصدير.',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
