INSERT INTO product_i18n (product_id,locale,title,slug,description,alt,tags,specifications,meta_title,meta_description,created_at,updated_at) VALUES ('d86a3615-720b-a870-9082-0c04960eac90','de','Savronik','savronik','<p>Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen und exportfertige Angebote.</p>','Savronik','[]','{}','Savronik — Sultan Defense','Teil des geprüften Hersteller- und Lieferantennetzwerks von Sultan Defense. Kontaktieren Sie unser Exportteam für B2B-Beschaffung, technische Spezifikationen un',NOW(3),NOW(3)) ON DUPLICATE KEY UPDATE title=VALUES(title),slug=VALUES(slug),description=VALUES(description),alt=VALUES(alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=NOW(3);
